84: func removeDuplicatesAndEmpty(values []string) []string {
85: 	encountered := map[string]struct{}{}
86: 	empty := true
87: 	var result []string
88: 	for _, v := range values {
89: 		if _, ok := encountered[v]; ok {
90: 			continue
91: 		}
92: 		encountered[v] = struct{}{}
93: 		empty = empty && v == ""
94: 		result = append(result, v)
95: 	}
96: 	if empty {
97: 		return nil
98: 	}
99: 	return result
100: }
